#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include "srad.h"

#define CHECK_CUDA_ERROR(cudaStatus) \
    do { \
        cudaStatus = cudaGetLastError(); \
        if (cudaStatus != cudaSuccess) { \
            fprintf(stderr, "cuda failed: %s\n", cudaGetErrorString(cudaStatus)); \
            exit(EXIT_FAILURE); \
        } \
    } while (0)

void random_matrix(float *I, int rows, int cols);

__global__ void srad_kernel(float *J, float *dN, float *dS, float *dW, float *dE, float *c, int rows, int cols, int *iN, int *iS, int *jW, int *jE, float lambda) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int idy = blockIdx.y * blockDim.y + threadIdx.y;

    if (idx < cols && idy < rows) {
        int k = idy * cols + idx;

        float Jc = J[k];

        // directional derivates
        dN[k] = J[iN[idy] * cols + idx] - Jc;
        dS[k] = J[iS[idy] * cols + idx] - Jc;
        dW[k] = J[idy * cols + jW[idx]] - Jc;
        dE[k] = J[idy * cols + jE[idx]] - Jc;

        float G2 = (dN[k] * dN[k] + dS[k] * dS[k] + dW[k] * dW[k] + dE[k] * dE[k]) / (Jc * Jc);

        float L = (dN[k] + dS[k] + dW[k] + dE[k]) / Jc;

        float num = (0.5 * G2) - ((1.0 / 16.0) * (L * L));
        float den = 1 + (.25 * L);
        float qsqr = num / (den * den);

        // diffusion coefficent (equ 33)
        den = (qsqr - 0.1) / (0.1 * (1 + 0.1));
        c[k] = 1.0 / (1.0 + den);

        // saturate diffusion coefficent
        if (c[k] < 0) { c[k] = 0; }
        else if (c[k] > 1) { c[k] = 1; }
    }
}

__global__ void srad_kernel2(float *J, float *c, int rows, int cols, float lambda) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int idy = blockIdx.y * blockDim.y + threadIdx.y;

    if (idx < cols && idy < rows) {
        int k = idy * cols + idx;

        // diffusion coefficent
        float cN = c[k];
        float cS = c[(idy + 1) * cols + idx];
        float cW = c[k];
        float cE = c[idy * cols + (idx + 1)];

        // divergence (equ 58)
        float D = cN * (J[(idy - 1) * cols + idx] - J[k]) + cS * (J[(idy + 1) * cols + idx] - J[k]) + cW * (J[idy * cols + (idx - 1)] - J[k]) + cE * (J[idy * cols + (idx + 1)] - J[k]);

        // image update (equ 61)
        J[k] = J[k] + 0.25 * lambda * D;
    }
}

void launch_srad_kernel(float *J, float *dN, float *dS, float *dW, float *dE, float *c, int rows, int cols, int *iN, int *iS, int *jW, int *jE, float lambda) {
    int blockSize = BLOCK_SIZE;
    dim3 block(blockSize, blockSize);
    dim3 grid((cols + blockSize - 1) / blockSize, (rows + blockSize - 1) / blockSize);

    srad_kernel<<<grid, block>>>(J, dN, dS, dW, dE, c, rows, cols, iN, iS, jW, jE, lambda);
    cudaDeviceSynchronize();

    srad_kernel2<<<grid, block>>>(J, c, rows, cols, lambda);
    cudaDeviceSynchronize();
}

int main(int argc, char* argv[]) {
    int rows, cols, size_I, size_R, niter = 10, iter, k;
    float *I, *J, q0sqr, sum, sum2, tmp, meanROI, varROI;
    float Jc, G2, L, num, den, qsqr;
    int *iN, *iS, *jE, *jW;
    float *dN, *dS, *dW, *dE;
    int r1, r2, c1, c2;
    float cN, cS, cW, cE;
    float *c, D;
    float lambda;
    int i, j;

    if (argc == 10) {
        rows = atoi(argv[1]);
        cols = atoi(argv[2]);
        if ((rows % 16 != 0) || (cols % 16 != 0)) {
            fprintf(stderr, "rows and cols must be multiples of 16\n");
            exit(1);
        }
        r1 = atoi(argv[3]);
        r2 = atoi(argv[4]);
        c1 = atoi(argv[5]);
        c2 = atoi(argv[6]);
        int nthreads = atoi(argv[7]);
        lambda = atof(argv[8]);
        niter = atoi(argv[9]);
    } else {
        fprintf(stderr, "Usage: %s <rows> <cols> <y1> <y2> <x1> <x2> <no. of threads><lamda> <no. of iter>\n", argv[0]);
        exit(1);
    }

    size_I = cols * rows;
    size_R = (r2 - r1 + 1) * (c2 - c1 + 1);

    I = (float*)malloc(size_I * sizeof(float));
    J = (float*)malloc(size_I * sizeof(float));
    c = (float*)malloc(size_I * sizeof(float));

    iN = (int*)malloc(rows * sizeof(int));
    iS = (int*)malloc(rows * sizeof(int));
    jW = (int*)malloc(cols * sizeof(int));
    jE = (int*)malloc(cols * sizeof(int));

    dN = (float*)malloc(size_I * sizeof(float));
    dS = (float*)malloc(size_I * sizeof(float));
    dW = (float*)malloc(size_I * sizeof(float));
    dE = (float*)malloc(size_I * sizeof(float));

    for (int i = 0; i < rows; i++) {
        iN[i] = i - 1;
        iS[i] = i + 1;
    }
    for (int j = 0; j < cols; j++) {
        jW[j] = j - 1;
        jE[j] = j + 1;
    }
    iN[0] = 0;
    iS[rows - 1] = rows - 1;
    jW[0] = 0;
    jE[cols - 1] = cols - 1;

    printf("Randomizing the input matrix\n");
    random_matrix(I, rows, cols);

    for (k = 0; k < size_I; k++) {
        J[k] = exp(I[k]);
    }

    printf("Start the SRAD main loop\n");

    for (iter = 0; iter < niter; iter++) {
        sum = 0; sum2 = 0;
        for (i = r1; i <= r2; i++) {
            for (j = c1; j <= c2; j++) {
                tmp = J[i * cols + j];
                sum += tmp;
                sum2 += tmp * tmp;
            }
        }
        meanROI = sum / size_R;
        varROI = (sum2 / size_R) - meanROI * meanROI;
        q0sqr = varROI / (meanROI * meanROI);

        float *dJ, *ddN, *ddS, *ddW, *ddE, *dc;
        cudaError_t cudaStatus;

        cudaStatus = cudaMalloc((void**)&dJ, size_I * sizeof(float));
        CHECK_CUDA_ERROR(cudaStatus);
        cudaStatus = cudaMalloc((void**)&ddN, size_I * sizeof(float));
        CHECK_CUDA_ERROR(cudaStatus);
        cudaStatus = cudaMalloc((void**)&ddS, size_I * sizeof(float));
        CHECK_CUDA_ERROR(cudaStatus);
        cudaStatus = cudaMalloc((void**)&ddW, size_I * sizeof(float));
        CHECK_CUDA_ERROR(cudaStatus);
        cudaStatus = cudaMalloc((void**)&ddE, size_I * sizeof(float));
        CHECK_CUDA_ERROR(cudaStatus);
        cudaStatus = cudaMalloc((void**)&dc, size_I * sizeof(float));
        CHECK_CUDA_ERROR(cudaStatus);

        cudaStatus = cudaMemcpy(dJ, J, size_I * sizeof(float), cudaMemcpyHostToDevice);
        CHECK_CUDA_ERROR(cudaStatus);

        launch_srad_kernel(dJ, ddN, ddS, ddW, ddE, dc, rows, cols, iN, iS, jW, jE, lambda);

        cudaStatus = cudaMemcpy(J, dJ, size_I * sizeof(float), cudaMemcpyDeviceToHost);
        CHECK_CUDA_ERROR(cudaStatus);

        cudaStatus = cudaFree(dJ);
        CHECK_CUDA_ERROR(cudaStatus);
        cudaStatus = cudaFree(ddN);
        CHECK_CUDA_ERROR(cudaStatus);
        cudaStatus = cudaFree(ddS);
        CHECK_CUDA_ERROR(cudaStatus);
        cudaStatus = cudaFree(ddW);
        CHECK_CUDA_ERROR(cudaStatus);
        cudaStatus = cudaFree(ddE);
        CHECK_CUDA_ERROR(cudaStatus);
        cudaStatus = cudaFree(dc);
        CHECK_CUDA_ERROR(cudaStatus);
    }

    printf("Computation Done\n");

    free(I);
    free(J);
    free(iN); free(iS); free(jW); free(jE);
    free(dN); free(dS); free(dW); free(dE);
    free(c);

    return 0;
}

void random_matrix(float *I, int rows, int cols) {
    srand(7);

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            I[i * cols + j] = rand() / (float)RAND_MAX;
        }
    }
}
